package check

import (
	"cmp"

	"github.com/stretchr/testify/assert"
	"github.com/stretchr/testify/require"

	"github.com/sourcegraph/sourcegraph/lib/core"
	"github.com/sourcegraph/sourcegraph/lib/errors"
)

func MustEqual[X comparable](t T, expected X, got X, msgAndArgs ...any) {
	t.Helper()
	require.Equal(t, expected, got, msgAndArgs...)
}

func Equal[X comparable](t T, expected X, got X, msgAndArgs ...any) bool {
	t.Helper()
	return assert.Equal(t, expected, got, msgAndArgs...)
}

func MustNotEqual[X comparable](t T, expected X, got X, msgAndArgs ...any) {
	t.Helper()
	require.NotEqual(t, expected, got, msgAndArgs...)
}

func NotEqual[X comparable](t T, expected X, got X, msgAndArgs ...any) bool {
	t.Helper()
	return assert.NotEqual(t, expected, got, msgAndArgs...)
}

func MustLess[X cmp.Ordered](t T, expected X, got X, msgAndArgs ...any) {
	t.Helper()
	require.Less(t, expected, got, msgAndArgs...)
}

func Less[X cmp.Ordered](t T, expected X, got X, msgAndArgs ...any) bool {
	t.Helper()
	return assert.Less(t, expected, got, msgAndArgs...)
}

func MustLessOrEqual[X cmp.Ordered](t T, expected X, got X, msgAndArgs ...any) {
	t.Helper()
	require.LessOrEqual(t, expected, got, msgAndArgs...)
}

func LessOrEqual[X cmp.Ordered](t T, expected X, got X, msgAndArgs ...any) bool {
	t.Helper()
	return assert.LessOrEqual(t, expected, got, msgAndArgs...)
}

func MustGreater[X cmp.Ordered](t T, expected X, got X, msgAndArgs ...any) {
	t.Helper()
	require.Greater(t, expected, got, msgAndArgs...)
}

func Greater[X cmp.Ordered](t T, expected X, got X, msgAndArgs ...any) bool {
	t.Helper()
	return assert.Greater(t, expected, got, msgAndArgs...)
}

func MustGreaterOrEqual[X cmp.Ordered](t T, expected X, got X, msgAndArgs ...any) {
	t.Helper()
	require.GreaterOrEqual(t, expected, got, msgAndArgs...)
}

func GreaterOrEqual[X cmp.Ordered](t T, expected X, got X, msgAndArgs ...any) bool {
	t.Helper()
	return assert.GreaterOrEqual(t, expected, got, msgAndArgs...)
}

func MustError(t T, err error, msgAndArgs ...any) {
	t.Helper()
	require.Error(t, err, msgAndArgs...)
}

func MustErrorIs(t T, expected error, got error, msgAndArgs ...any) {
	core.AssertPrecondition(expected != nil, "use check.MustNoError for asserting lack of an error")
	if got == nil {
		require.FailNow(t, "expected non-nil error", msgAndArgs...)
	}
	require.True(t, errors.Is(got, expected), msgAndArgs)
}

func Error(t T, err error, msgAndArgs ...any) bool {
	t.Helper()
	return assert.Error(t, err, msgAndArgs...)
}

func ErrorIs(t T, expected error, got error, msgAndArgs ...any) bool {
	core.AssertPrecondition(expected != nil, "use check.MustNoError for asserting lack of an error")
	if got == nil {
		return assert.FailNow(t, "expected non-nil error", msgAndArgs...)
	}
	return assert.True(t, errors.Is(got, expected), msgAndArgs)
}

func NotErrorIs(t T, expected error, got error, msgAndArgs ...any) bool {
	t.Helper()
	return assert.NotErrorIs(t, expected, got, msgAndArgs...)
}

func MustErrorAs(t T, err error, target any, msgAndArgs ...any) bool {
	t.Helper()
	return assert.ErrorAs(t, err, target, msgAndArgs...)
}

func ErrorIsType(t T, expected error, got error, msgAndArgs ...any) bool {
	t.Helper()
	assert.Error(t, got)

	// Check if the expected type exists anywhere in the error chain using errors.As
	// This handles both direct matches and wrapped errors
	return assert.True(t, errors.As(got, &expected),
		append(msgAndArgs, "Expected error type %T not found in error chain, got %T", expected, got)...)
}

func MustNoError(t T, err error, msgAndArgs ...any) {
	t.Helper()
	require.NoError(t, err, msgAndArgs...)
}

func NoError(t T, err error, msgAndArgs ...any) bool {
	t.Helper()
	return assert.NoError(t, err, msgAndArgs...)
}

func MustErrorContains(t T, err error, contains string, msgAndArgs ...any) {
	t.Helper()
	require.ErrorContains(t, err, contains, msgAndArgs...)
}

func ErrorContains(t T, err error, contains string, msgAndArgs ...any) bool {
	t.Helper()
	return assert.ErrorContains(t, err, contains, msgAndArgs...)
}

// MustLen asserts that the given slice has a particular length.
//
// The second argument is the expected value for consistency with other APIs,
// where the expected value comes before the obtained value.
func MustLen[S ~[]E, E any](t T, expectedLen int, c S, msgAndArgs ...any) {
	t.Helper()
	require.Len(t, c, expectedLen, msgAndArgs...)
}

// Len asserts that the given slice has a particular length.
//
// The second argument is the expected value for consistency with other APIs,
// where the expected value comes before the obtained value.
func Len[S ~[]E, E any](t T, expectedLen int, c S, msgAndArgs ...any) bool {
	t.Helper()
	return assert.Len(t, c, expectedLen, msgAndArgs...)
}

func Fail(t T, msg string, args ...any) {
	t.Helper()
	assert.Fail(t, msg, args...)
}

func MustFail(t T, msg string, args ...any) {
	t.Helper()
	require.Fail(t, msg, args...)
}

func MustTrue[B ~bool](t T, b B, msgAndArgs ...any) {
	t.Helper()
	require.True(t, bool(b), msgAndArgs...)
}

func True[B ~bool](t T, b B, msgAndArgs ...any) bool {
	t.Helper()
	return assert.True(t, bool(b), msgAndArgs...)
}

func MustFalse[B ~bool](t T, b B, msgAndArgs ...any) {
	t.Helper()
	require.False(t, bool(b), msgAndArgs...)
}

func False[B ~bool](t T, b B, msgAndArgs ...any) bool {
	t.Helper()
	return assert.False(t, bool(b), msgAndArgs...)
}

func MustNilPtr[X any](t T, p *X, msgAndArgs ...any) {
	t.Helper()
	require.Nil(t, p, msgAndArgs...)
}

func NilPtr[X any](t T, p *X, msgAndArgs ...any) bool {
	t.Helper()
	return assert.Nil(t, p, msgAndArgs...)
}

func MustNotNilPtr[X any](t T, p *X, msgAndArgs ...any) {
	t.Helper()
	require.NotNil(t, p, msgAndArgs...)
}

func NotNilPtr[X any](t T, p *X, msgAndArgs ...any) bool {
	t.Helper()
	return assert.NotNil(t, p, msgAndArgs...)
}

func MustIff(t T, b1 bool, b2 bool, msgAndArgs ...any) {
	t.Helper()
	require.Equal(t, b1, b2, msgAndArgs...)
}

func Iff(t T, b1 bool, b2 bool, msgAndArgs ...any) {
	t.Helper()
	assert.Equal(t, b1, b2, msgAndArgs...)
}

func MustPanicWith[A any](t T, expected A, f func()) {
	t.Helper()
	defer func() {
		if r := recover(); r != nil {
			if ra, ok := r.(A); ok {
				MustNoDiff(t, expected, ra, "panic value")
			} else {
				t.Fatalf("failed to cast recovered value %v to type %T", r, expected)
			}
		} else {
			t.Fatalf("expected a panic with value %v, but the function did not panic", expected)
		}
	}()
	f()
}

func PanicWith[A any](t T, expected A, f func()) {
	t.Helper()
	defer func() {
		if r := recover(); r != nil {
			if ra, ok := r.(A); ok {
				NoDiff(t, expected, ra, "panic value")
			} else {
				t.Errorf("failed to cast recovered value %v to type %T", r, expected)
			}
		} else {
			t.Errorf("expected a panic with value %v, but the function did not panic", expected)
		}
	}()
	f()
}

// MustUnwrap is a wrapper for MustNoError for compressing code vertically.
//
// For example:
//
//	xyz, err := someOp(...)
//	check.MustNoError(t, err)
//
// can be replaced with
//
//	xyz := check.MustUnwrap(someOp(...))(t)
//
// The function signature is a bit unusual to avoid explicit type annotations,
// while maintaining the ability to directly unpack two return values
// as the two parameters.
func MustUnwrap[A any](v A, err error) func(t T) A {
	return func(t T) A {
		MustNoError(t, err)
		return v
	}
}

func MustNotEmpty(t T, v any, msgAndArgs ...any) {
	t.Helper()
	require.NotEmpty(t, v, msgAndArgs...)
}

func MustEmpty(t T, v any, msgAndArgs ...any) {
	t.Helper()
	require.Empty(t, v, msgAndArgs...)
}

func MustJSONEqual(t T, expected, actual string, msgAndArgs ...any) {
	t.Helper()
	require.JSONEq(t, expected, actual, msgAndArgs...)
}

