package images

import (
	"bytes"
	"encoding/binary"
	"hash/crc32"
	"image"
	"image/color"
	"image/png"
	"testing"

	"github.com/sourcegraph/sourcegraph/lib/check"
)

// createBombPNG creates a valid PNG whose IHDR claims dimensions of width×height,
// but contains only a tiny 1×1 pixel of actual image data. This simulates a
// decompression bomb: a small file that claims to expand to a huge image.
func createBombPNG(tb testing.TB, width, height int) []byte {
	tb.Helper()

	// Encode a real 1×1 PNG as a base.
	img := image.NewRGBA(image.Rect(0, 0, 1, 1))
	img.Set(0, 0, color.RGBA{R: 255, G: 0, B: 0, A: 255})
	var buf bytes.Buffer
	if err := png.Encode(&buf, img); err != nil {
		tb.Fatalf("failed to encode base PNG: %v", err)
	}
	data := buf.Bytes()

	// PNG binary layout:
	//   [0:8]   - PNG signature
	//   [8:12]  - IHDR chunk length (= 13)
	//   [12:16] - chunk type "IHDR"
	//   [16:20] - width  (big-endian uint32)
	//   [20:24] - height (big-endian uint32)
	//   [24:29] - bit depth, colour type, compression, filter, interlace
	//   [29:33] - CRC32 over bytes [12:29]

	// Patch width and height.
	binary.BigEndian.PutUint32(data[16:20], uint32(width))
	binary.BigEndian.PutUint32(data[20:24], uint32(height))

	// Recompute the IHDR CRC (covers chunk type + chunk data = bytes [12:29]).
	h := crc32.NewIEEE()
	h.Write(data[12:29])
	binary.BigEndian.PutUint32(data[29:33], h.Sum32())

	return data
}

// TestProcessImageData_DecompressionBomb verifies that an image whose declared
// pixel count exceeds MaxDecodedPixels is rejected before the full decode.
func TestProcessImageData_DecompressionBomb(t *testing.T) {
	// Dimensions that produce > MaxDecodedPixels (50 MP).
	// 8000 × 7000 = 56 000 000 pixels > 50 000 000.
	data := createBombPNG(t, 8000, 7000)

	_, _, err := processImageData(data, "image/png")
	check.MustError(t, err)
	check.MustErrorContains(t, err, "exceed maximum allowed pixels")
}

// TestProcessImageData_NormalImage_NotRejected verifies that a normal-sized
// image is still accepted and processed correctly.
func TestProcessImageData_NormalImage_NotRejected(t *testing.T) {
	// A modest 200×200 gradient image — well within all limits.
	data := createTestImage(t, 200, 200)

	result, mimeType, err := processImageData(data, "image/png")
	check.NoError(t, err)
	if mimeType != "image/png" && mimeType != "image/jpeg" {
		t.Errorf("unexpected mime type: %s", mimeType)
	}
	if len(result) == 0 {
		t.Error("expected non-empty result")
	}
}

// TestProcessImageData_AtPixelLimit verifies that an image right at the limit
// is accepted.
func TestProcessImageData_AtPixelLimit(t *testing.T) {
	// 7071 × 7071 ≈ 49 999 041 pixels, just under 50 MP.
	data := createBombPNG(t, 7071, 7071)

	// DecodeConfig succeeds (dimensions are within limit).
